import { Component, computed, OnDestroy, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { Subscription } from 'rxjs';
import { CentsPipe } from '../../shared/cents.pipe';
import { Unit } from '../../core/models';

type Occupancy = 'occupied' | 'vacant';
type StatusFilter = '' | Occupancy;

@Component({
  selector: 'app-units-list',
  standalone: true,
  imports: [CommonModule, RouterLink, CentsPipe],
  templateUrl: './units-list.component.html',
  styleUrl: './units-list.component.css',
})
export class UnitsListComponent implements OnInit, OnDestroy {
  readonly loading = signal(false);
  readonly error = signal('');

  /** All units in the portfolio. */
  readonly units = signal<Unit[]>([
    { id: 'u1', number: '101', bedrooms: 1, rentCents: 120000 },
    { id: 'u2', number: '102', bedrooms: 2, rentCents: 180000 },
    { id: 'u3', number: '201', bedrooms: 2, rentCents: 190000 },
    { id: 'u4', number: '202', bedrooms: 3, rentCents: 240000 },
  ]);

  /** Occupancy by unit id — 202 (u4) is vacant. */
  private readonly occupancy: Record<string, Occupancy> = {
    u1: 'occupied',
    u2: 'occupied',
    u3: 'occupied',
    u4: 'vacant',
  };

  /** Active filter, synced from the `status` query param. */
  readonly statusFilter = signal<StatusFilter>('');

  /** Units after applying the active status filter. */
  readonly filtered = computed<Unit[]>(() => {
    const filter = this.statusFilter();
    const list = this.units();
    if (!filter) return list;
    return list.filter((u) => this.statusOf(u.id) === filter);
  });

  private sub?: Subscription;

  constructor(private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.sub = this.route.queryParamMap.subscribe((params) => {
      const raw = params.get('status');
      this.statusFilter.set(raw === 'occupied' || raw === 'vacant' ? raw : '');
    });
  }

  ngOnDestroy(): void {
    this.sub?.unsubscribe();
  }

  statusOf(id: string): Occupancy {
    return this.occupancy[id] ?? 'vacant';
  }
}
